<template>
  <section>
    <v-carousel cycle :height="carouselHeight" reverse-transition="fade-transition" transition="fade-transition" class="grey darken-4">
      <v-carousel-item contain v-for="(item,i) in carousel" :key="i" :src="item.img" @click="expandFile({type: 'open_window', src:item.page})"></v-carousel-item>
    </v-carousel>
    <!-- barra de bavegacion -->
    <div class="text-center">
      <v-sheet class="mx-auto" color="#5f1b2d" dark>
        <v-btn class="ma-1 card-link" color="white" plain small to="/"> inicio </v-btn>
        <v-btn class="ma-1 card-link" color="white" plain small to="/materiales-didacticos"> material didácticos </v-btn>
        <v-btn class="ma-1 card-link" color="white" plain small to="/2019-2024"> 2019-2024 </v-btn>
      </v-sheet>
    </div>
  </section>
</template>

<script>
import { mapActions, mapState } from 'vuex'

export default {
  name: 'HeaderCard',
  data () {
    return {
      carousel: []
    }
  },
  computed: {
    ...mapState('S20242030', [
      'carouselHeight'
    ])
  },
  methods: {
    ...mapActions('S20242030', [
      'setUrl',
      'updateWindowWidth',
      'expandFile',
      'loadData'
    ]),
    handleResize () {
      this.updateWindowWidth()
    }
  },
  destroyed () {
    window.removeEventListener('resize', this.handleResize)
  },
  async created () {
    window.addEventListener('resize', this.handleResize)
    this.handleResize()
    this.carousel = await this.loadData(`${process.env.VUE_APP_API_URL}20192024/json/carousel.json`)
    // console.log('carousel --> ', this.carousel)
  }
}
</script>
